        proxyAuth := fmt.Sprintf("%s:%s", tb.proxyUsername, tb.proxyPassword)
        basicAuth := "Basic " + base64.StdEncoding.EncodeToString([]byte(proxyAuth))
        tr.Proxy = http.ProxyURL(&url.URL{
            Scheme:   tb.proxyURL.Scheme,
            Host:     tb.proxyURL.Host,
            RawQuery: "basic=" + basicAuth,
        })
    }

    client := &http.Client{
        Transport: tr,
        Timeout:   tb.timeout,
    }

    return client, nil
}
