void copyGridToDevice(CellState* hostGrid, CellState** deviceGrid, int width, int height) {
    cudaMalloc(deviceGrid, width * height * sizeof(CellState));
    cudaMemcpy(*deviceGrid, hostGrid, width * height * sizeof(CellState), cudaMemcpyHostToDevice);
}

void copyGridFromDevice(CellState* hostGrid, CellState* deviceGrid, int width, int height) {
    cudaMemcpy(hostGrid, deviceGrid, width * height * sizeof(CellState), cudaMemcpyDeviceToHost);
    cudaFree(deviceGrid);
}
```

### Шаг 4: Запуск симуляции

Для запуска симуляции необходимо вызвать функцию ядра с соответствующими параметрами.

```cpp
void runGameOfLife(CellState* grid, int width, int height, int iterations) {
    CellState* deviceGrid;
    CellState* newDeviceGrid;

    copyGridToDevice(grid, &deviceGrid, width, height);
    cudaMalloc(&newDeviceGrid, width * height * sizeof(CellState));

    dim3 blockSize(16, 16);
    dim3 gridSize((width + blockSize.x - 1) / blockSize.x, (height + blockSize.y - 1) / blockSize.y);

    for (int i = 0; i < iterations; ++i) {
        gameOfLifeKernel<<<gridSize, blockSize>>>(deviceGrid, newDeviceGrid, width, height);
        cudaDeviceSynchronize();

        // Обмен буферами
        CellState* temp = deviceGrid;
        deviceGrid = newDeviceGrid;
        newDeviceGrid = temp;
    }

    copyGridFromDevice(grid, deviceGrid, width, height);
    cudaFree(newDeviceGrid);
}
```

